ReactDOM.render(
  <React.StrictMode>
    {users.map((user,i) =>
      <Profile2 
          key={i}
          name={user.name}
          tag={user.tag}
          location={user.location}
          avatar={user.avatar}
          stats={user.stats}
      />
    )}
  </React.StrictMode>,
